const body = $json.body ?? $json;
const answers = body.answers ?? body.submission?.questions ?? body.questions ?? {};
const get = (...keys) => {
  for (const key of keys) {
    const direct = answers[key];
    if (direct !== undefined && direct !== null && direct !== '') return direct;
  }
  return '';
};
const borrowerProfiles = [];
if (get('employment_type', 'borrower_profile')?.toString().includes('שכיר')) borrowerProfiles.push('salaried');
if (get('employment_type', 'borrower_profile')?.toString().includes('עצמאי')) borrowerProfiles.push('self-employed');
const caseTypeMap = {
  'רכישה דירה יחידה': 'purchase-single-dwelling',
  'רכישת דירה חלופית': 'purchase-replacement-dwelling',
  'דירה להשקעה': 'purchase-investment-dwelling',
  'מחזור': 'refinance',
  'לכל מטרה': 'all-purpose-against-home',
  'מחיר למשתכן/דירה בהנחה': 'discounted-program',
  'בניה עצמית': 'self-build',
  'שיפוץ': 'renovation',
};
const documentSeeds = [
  'id-card',
  'advisor-authorization',
  'bank-statements-3m',
  'loan-summary',
  'tabu-extract'
];
if (borrowerProfiles.includes('salaried')) documentSeeds.push('payslips-3m');
if (borrowerProfiles.includes('self-employed')) documentSeeds.push('accountant-confirmation');
const caseTypeRaw = get('case_type', 'transaction_type');
const caseType = caseTypeMap[caseTypeRaw] ?? 'purchase-single-dwelling';
if (['purchase-single-dwelling', 'purchase-replacement-dwelling', 'purchase-investment-dwelling', 'discounted-program'].includes(caseType)) {
  documentSeeds.push('sale-agreement');
}
if (caseType === 'renovation') documentSeeds.push('renovation-quote');
const now = new Date().toISOString();
return [{
  json: {
    sourceSubmissionId: body.submissionId ?? body.submission_id ?? body.id ?? now,
    caseFields: {
      'Lead name': get('full_name', 'lead_name'),
      'Spouse name': get('spouse_name'),
      Phone: get('phone', 'mobile'),
      Email: get('email'),
      'Case type': caseType,
      'Borrower profiles': borrowerProfiles,
      'Current stage': 'intake-submitted',
      'Assigned staff': 'Unassigned',
      'Missing items count': [...new Set(documentSeeds)].length,
      'Client portal status': 'pending-office-approval',
      'Fillout submission id': body.submissionId ?? body.submission_id ?? body.id ?? '',
      Notes: get('notes', 'free_text')
    },
    clientFields: {
      'Full name': get('full_name', 'lead_name'),
      'ID number': get('teudat_zehut', 'id_number'),
      'Preferred language': get('language_preference') || 'he',
      'WhatsApp number': get('phone', 'mobile')
    },
    documentSeeds: [...new Set(documentSeeds)],
    activityFields: {
      Actor: 'system',
      'Event type': 'intake_received',
      Summary: 'Fillout intake captured and case seeded',
      'Source system': 'fillout',
      Timestamp: now,
    },
    officeNotification: {
      channel: 'whatsapp',
      text: `ליד חדש נכנס ל-KeyPoint עבור ${get('full_name', 'lead_name')} — נא לבדוק ולאשר פתיחת תיק.`
    }
  }
}];

const caseId = $item(0).$node["Create case in Airtable"].json.id;
return ($json.documentSeeds || []).map((code) => ({
  json: {
    'Case link': [caseId],
    'Document code': code,
    'Required?': true,
    Status: 'not-uploaded'
  }
}));
